// Script Continued Below
var taskerDynamicFilters = Class.create();
taskerDynamicFilters.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	// STRY0131148 - adding a new member to an office, return the list of active users not already in this office
	getNewMembersFilter: function(rec){
		var arrMembersInOU = [];
		var strMembersInOU = 'None';
		var query = '';
		var OUID = rec.discover_office_hierarchy;
		if(OUID && (OUID + '' !="")){
			arrMembersInOU = this.getOUMemberList(rec.discover_office_hierarchy);
			strMembersInOU = arrMembersInOU.join(',');
			query = "sys_id NOT IN " + strMembersInOU + '^active=true';
			return query;
		} else {
			// if not a new record do not allow changing
			return "sys_id IN " + strMembersInOU;
		}
	},

	// STRY0131148 - get users in office to filter out when adding a user to the office
	getOUMemberList: function(OUID){
		var members = [];
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMembers.addQuery('discover_office_hierarchy', OUID);
		grMembers.query();
		while(grMembers.next()){  
			members.push(grMembers.getValue('office_member'));
		}
		return members;  
	},

	// STRY0131148 
	getOfficesWhereUserIsMemberOfList: function(rec){
		var user;
		var arrOffices = [];
		var currentOU;

		if(rec.u_tasker_user){
			user = rec.getValue("u_tasker_user");
		} else if(rec.office_member) {
			user = rec.getValue("office_member");
		}
		var strOffices = "-1";
		if(user && user != ''){
			arrOffices = new tasking_System_Settings_Scripts().getOUsWhereUserIsAMember(user);
		}
		currentOU = rec.getValue("discover_office_hierarchy");
		if(currentOU && currentOU !=''){
			if(arrOffices.indexOf(currentOU) == -1){
				arrOffices.push(currentOU);
			}
		}
		strOffices = arrOffices.join(',');			

		return 	'sys_id IN ' + strOffices  + '' + '^active=true';
	},

	// STRY0111621
	getReviewers: function() {
		return this.getAllMembersCurrentUserCanTask();
	},
	// STRY0111621
	getOnBehalfOf: function() {
		return this.getAllMembersCurrentUserCanTask();
	},

	// STRY0111621
	getTemplateReviewers: function(){
		return this.getOUSubTaskMembersInTemplates();
	},

	// STRY0111621
	getTemplateOnBehalfOf: function(){
		return this.getOUSubTaskMembersInTemplates();
	},

	// DFCT0012050 
	getUserRestrictedGroupEncodedQuery: function(){
		var userRestrictedGroupFitler = '';
		var myRestrictedGroups = [];
		myRestrictedGroups = this.getMyRestrictedGroupsArray();
		userRestrictedGroupFitler = "^assignment_groupISEMPTY";
		if(myRestrictedGroups.length>0){
			userRestrictedGroupFitler = userRestrictedGroupFitler + "^ORassignment_groupIN" + myRestrictedGroups.join(",");
		}
		return userRestrictedGroupFitler;
	},

	getMyRestrictedGroupsArray: function(){
		var myRestrictedGroups = [];
		var au = new global.ArrayUtil();
		var objAllUsersGroups = gs.getUser().getMyGroups();
		var arrAllUsersGroups = au.convertArray(objAllUsersGroups);
		var arrAllRestrictedGroups = this.getAllRestrictedGroups();
		myRestrictedGroups = au.intersect(arrAllUsersGroups, arrAllRestrictedGroups);
		return myRestrictedGroups;		
	},

	getAllRestrictedGroups: function(){
		var arrRestrictedGroups = [];
		var restrictedGroupID = "";
		// previously hard coded type id61734f1adb5ea740bb8ee536ca9619c1
		restrictedGroupID = this.getRestrictedGroupTypeID();

		// have to use glide record b/c user might not have permissions.  We are not returning this list, but only using it to filter another list.
		var grGroups = new GlideRecord("sys_user_group");
		var groupQuery = "typeLIKE" + restrictedGroupID;
		grGroups.addEncodedQuery(groupQuery);
		grGroups.query();
		while (grGroups.next()){
			arrRestrictedGroups.push(grGroups.getUniqueValue());
		}
		return arrRestrictedGroups;
	},

	// STRY0096033 - Remove restriction group type hardcode sysid in Tasker
	getMyRestrictedGroups: function() {
		var filter = '';
		var myGroups = 'none';
		var restrictedGroupID = "";
		// previously hard coded type id61734f1adb5ea740bb8ee536ca9619c1
		restrictedGroupID = this.getRestrictedGroupTypeID();
		if(restrictedGroupID!=""){
			myGroups = gs.getUser().getMyGroups();
			filter = 'typeLIKE' + restrictedGroupID + '^sys_id IN ' + myGroups;	
		}
		return filter; 
	},

	getRestrictedGroupTypeID: function(){
		var restrictedGroupTypeID = '';
		var groupTypeName = gs.getProperty('x_153465_discovert.Restricted Group Type Name') + '';
		if( groupTypeName != ''){
			// look up type by name to get the ID.  ID will be used in query below
			var gr_groupType = new GlideRecord('sys_user_group_type');
			gr_groupType.addQuery('name', groupTypeName);
			gr_groupType.query();
			if(gr_groupType.next()){
				restrictedGroupTypeID = gr_groupType.getUniqueValue();
			}
		}
		return restrictedGroupTypeID;

	},

	// STRY0099013 - change filter for Task Owner
	getTaskOnwers: function() {
		return this.getAllMembersCurrentUserCanTask();
	},

	getSubTaskMembers: function() {
		return this.getAllMembersCurrentUserCanTask();
	},

	// STRY0099013 - change filter for Task Owner
	getAllMembersCurrentUserCanTask: function() {
		// STRY0064991 - get users for members
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617
		var taskPrivacy = new task_privacy();
		// DFCT0011930
		var primary_office = '';
		// Task Privacy
		var recordPrivacy = current.u_privacy;

		// STRY0079512
		var restrictedGroup = '';
		if(current.getTableName() == 'x_153465_discovert_route_task_instance'){
			restrictedGroup = current.assignment_group + '';
			// DFCT0011930
			primary_office = current.primary_office + '';

		} else{
			var templateData = {};
			templateData = this.getTemplateInfo();
			restrictedGroup = templateData.restricted_group == null ? '': templateData.restricted_group;
			// DFCT0011930
			primary_office = templateData.primary_office;
		}

		var ouMemArr = [];
		var arrOUs = [];
		// DFCT0011930 - user primary office to determine Task Administrator permissions
		var isTaskAdministrator = UserPermissions.userIsTaskAdministratorForOU(primary_office);
		// DFCT0011930 - user primary office to determine Task Executive permissions
		var isTaskExecutive = UserPermissions.userIsTaskExecutiveForOU(primary_office);

		// if user is a Task Administrator, return all users
		// STRY0112587 - DFCT0011930
		if (isTaskAdministrator || isTaskExecutive){
			// RJ - STRY0065162 - fix issue where all active users was returned for members, instead of only users with Task_User role were returned
			// STRY0078831 - fixed issue where Adminstrators would see all users when a restricted group was selected.
			if (restrictedGroup != '') {
				ouMemArr = UserPermissions.getAllMembersSysIdsInGroup(restrictedGroup);
				return 'sys_id IN ' + ouMemArr.join(',')  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 				
			} else{
				// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617
				ouMemArr = taskPrivacy.getAllUsersAdminsCanTask();
			}
		}
		// now determine if user is a the Task Manager for the selected Primary Assignee
		// now determine if user is a the Task Manager for the selected Primary Assignee
		else {
			// note if primary assignee is not the restriction, we would get all OUs where the user is a Task Manager
			// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617 - changed to apply privacy settings
			arrOUs = taskPrivacy.getMyOUTaskManagersPrivacyFiltered(gs.getUserID(), primary_office, recordPrivacy);

			// STRY0112462
			// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617
			var permissiveOffices = taskPrivacy.getPermissiveOUsPrivacyFiltered();
			arrOUs = arrOUs.concat(permissiveOffices);

			if (arrOUs.length > 0 ){
				ouMemArr = taskingScripts.retrieveMembersInOus(arrOUs);
				// DFCT0010767
				ouMemArr.push(gs.getUserID());
			} else{  // if the user has no members returned from the taking management role, just set add the user
				ouMemArr.push(gs.getUserID());
			}			
		}
		// now limit to restricted group, if necessary
		if (restrictedGroup != '') 
			ouMemArr = this.limitUsersToRestrictedGroup(ouMemArr, restrictedGroup);
		// turn array into a comma delimitted string.
		var sMems = ouMemArr.join(',');
		// RJ - STRY0065162 - fix issue where all active users was returned for members, instead of only users with Task_User role were returned
		return 'sys_id IN ' + sMems  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 
	},

	// STRY0075850 load contacts for task and template forms based on the selected OUs
	getExternalContacts: function(gr) {
		var returnfilter = 'sys_id IN ';

		if(gr.getRecordClassName() == 'x_153465_discovert_route_task_instance'){
			if(gr.tasking_authority && gr.parent.nil() && gr.tasking_authority.u_external_flag){
					returnfilter = this.getContactsForOu(gr.getValue('assignment_group'), gr.getValue('tasking_authority'));
			} else if(gr.u_external_ou) {
				returnfilter = this.getContactsForOu(gr.getValue('assignment_group'), gr.getValue('u_external_ou'));
			}
		}
		if(gr.getRecordClassName() == 'x_153465_discovert_route_tasks'){
			if(gr.tasking_authority && gr.parent.nil() && gr.tasking_authority.u_external_flag){
					returnfilter = this.getContactsForOu(gr.getValue('assigned_to_group'), gr.getValue('tasking_authority'));
			} else if(gr.u_external_ou) {
				returnfilter = this.getContactsForOu(gr.getValue('assigned_to_group'), gr.getValue('u_external_ou'));
			}
		}
		if(gr.getRecordClassName() == 'x_153465_discovert_discover_routing_template' ||
			gr.getRecordClassName() == 'x_153465_discovert_discover_routing_runtime'){
			if(gr.u_tasking_authority && gr.u_tasking_authority.u_external_flag){
					returnfilter = this.getContactsForOu(gr.getValue('u_restricted_group'), gr.getValue('u_tasking_authority'));
			} else if(gr.u_external_ou) {
				returnfilter = this.getContactsForOu(gr.getValue('u_restricted_group'), gr.getValue('u_external_ou'));
			} 
		}
		return returnfilter;
	},

	// STRY0074595 - loads Members for Internal OU and Contacts for External OU
	getPrimaryContactFilterForOu: function(gr) {
		var contacts = [];
		var sOU = gr.getUniqueValue();
		if(gr.u_external_flag==true){
			var grContacts = new GlideRecordSecure('x_153465_discovert_organizational_contacts');
			grContacts.addQuery('u_contact_ou', sOU);
			grContacts.query();
			while(grContacts.next()){
				contacts.push(grContacts.getValue('u_user_information'));
			}
		}else{
			var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
			grMembers.addQuery('discover_office_hierarchy', sOU);
			grMembers.query();
			while(grMembers.next()){
				contacts.push(grMembers.getValue('office_member'));
			}
		}
		return 'sys_id IN ' + contacts.join(',');  	
	},

	// STRY0074671 - Display all the active Contacts for the OU provided
	getContactsForOu: function(restrictedGroup, sOU) {
		var ouMemArr = [];
		var contacts = [];
		var grContacts = new GlideRecordSecure('x_153465_discovert_organizational_contacts');
		grContacts.addQuery('u_contact_ou', sOU);
		if(restrictedGroup != null && restrictedGroup != ''){
			ouMemArr = new UserInfoScripts().getAllMembersSysIdsInGroup(restrictedGroup);
			grContacts.addQuery('u_user_information', 'IN', ouMemArr.join(','));
		}
		grContacts.query();
		while(grContacts.next()){
			contacts.push(grContacts.getValue('u_user_information'));
		}
		return 'sys_id IN ' + contacts.join(',');  	
	},

	//Display all the  active OU's where the current user is an OU Process Template Admin
	getMyOUProcessTemplateAdminOUs: function() {	
			var user = gs.getUserID();
			var offices = [];
			var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
			grOUs.addQuery('has_ou_process_rights', 'true');
			grOUs.addQuery('office_member', user);
			grOUs.query();


			while(grOUs.next()){
				offices.push(grOUs.getValue('discover_office_hierarchy'));    
			}
		//  STRY0068500
		return 'sys_id IN ' + offices.join(',');  	
	},

	// STRY0065017 - get members in Template Screens
	getOUMembersInTemplates: function() {
		var templateData = {};
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		// DFCT0011850 - DFCT0011849 
		var taskPrivacy = new task_privacy();
		var ouMemArr = [];
		var arrOUs = [];
		templateData = this.getTemplateInfo();
		// DFCT0012402
		var recordTable = current.getTableName();
		var userCanRun = UserPermissions.userCanRunTemplateForTemplateId(templateData.templateId);

		// handle my-template first as it is the easiest
		if (templateData.template_level == 'my_process'){
			// the rules for my template level are the same as the rules for the user.  return getOUMembers
			return this.privategetOUMembers(templateData.primary_assignee, templateData.restricted_group);
		} else if (templateData.template_level == 'ou_process') {
			// DFCT0012402
			// handle OU level next it is more complex
			if (UserPermissions.userHasOUProcessRights(templateData.template_ou) || (recordTable == 'x_153465_discovert_discover_routing_runtime'  && userCanRun)) {
				// note if primary assignee is not the restriction, we would get all OUs where the user is a Task Manager
				// for the template, the selected OU selected for the process also has match the primary assignee for the user to be able to 
				// select users from the OU.
				if (templateData.primary_assignee && templateData.primary_assignee != '') {
					// DFCT0011319 - code was handling the case where there is a primary assignee and it matches the OU
					if (templateData.primary_assignee == templateData.template_ou ){
						arrOUs.push(templateData.primary_assignee);
						// based on note above, if this isn't limitted to primary assignee, just return that load
						ouMemArr = taskingScripts.retrieveMembersInOus(arrOUs);
					// DFCT0011319 - added code to handle the case where there is a primary assignee and it does NOT matches the OU
					} else {
						return this.privategetOUMembers(templateData.primary_assignee, templateData.restricted_group);					
					}

				} else{
					// STRY0065247 - If no Primary assignee set, then return all members based on Template and user
					// DFCT0011892 - OU level templates task as a task manager of the template OU.  So, the people should be restricted to the people in the Template OU.
					// DFCT0012071
					ouMemArr = this._getAllMembersTemplateCanTask(templateData.template_ou, templateData.primary_office, templateData.recordPrivacy);
				}	
			}
		} else if (templateData.template_level == 'global_process') {
			// DFCT0012402
			if (UserPermissions.userHasGlobalProcessRights() || (recordTable == 'x_153465_discovert_discover_routing_runtime'  && userCanRun)){
				if (templateData.primary_assignee && templateData.primary_assignee != ''){
					arrOUs.push(templateData.primary_assignee);
					// member field is limtted to the selected Primary Assignee
					ouMemArr = taskingScripts.retrieveMembersInOus(arrOUs);
				} else{
					// DFCT0011850 - DFCT0011849 DFCT0011927 - restricted group is filtered out below.  So, get all users the global designer can task
					ouMemArr = taskPrivacy.getAllUsersAdminsCanTask();
				}
			}
		}		
		// now limit to restricted group, if necessary
		if ( templateData.restricted_group != '') 
			ouMemArr = this.limitUsersToRestrictedGroup(ouMemArr, templateData.restricted_group);
		// turn array into a comma delimitted string.
		var sMems = ouMemArr.join(',');
		// RJ - STRY0065162 - fix issue where all active users was returned for members, instead of only users with Task_User role were returned
		return 'sys_id IN ' + sMems  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 
	},

	// STRY0079512 - fixed an issue loading members for getting members when createing multi sub tasks.  It was limited to just the Primary Assignee OU selected. 
	getOUSubTaskMembersInTemplates: function() {
		var templateData = {};
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		// DFCT0011850 - DFCT0011849 
		var taskPrivacy = new task_privacy();

		var ouMemArr = [];
		var arrOUs = [];
		templateData = this.getTemplateInfo();
		// DFCT0012402
		var recordTable = current.getTableName();
		var userCanRun = UserPermissions.userCanRunTemplateForTemplateId(templateData.templateId);

		// handle my-template first as it is the easiest
		if (templateData.template_level == 'my_process'){
			return this.getSubTaskMembers();
		} else if (templateData.template_level == 'ou_process') {
			// DFCT0012402
			// handle OU level next it is more complex
			if (UserPermissions.userHasOUProcessRights(templateData.template_ou) || (recordTable == 'x_153465_discovert_discover_routing_runtime'  && userCanRun)) {
				// STRY0065247 - If no Primary assignee set, then return all members based on Template and user
				// DFCT0011892 - OU level templates task as a task manager of the template OU.  So, the people should be restricted to the people in the Template OU.
				// DFCT0012071					
				ouMemArr = this._getAllMembersTemplateCanTask(templateData.template_ou, templateData.primary_office, templateData.recordPrivacy);
			}
		} else if (templateData.template_level == 'global_process') {
			// DFCT0012402
			if (UserPermissions.userHasGlobalProcessRights() || (recordTable == 'x_153465_discovert_discover_routing_runtime'  && userCanRun)){
				if (templateData.restricted_group != '') {
					ouMemArr = UserPermissions.getAllMembersSysIdsInGroup(templateData.restricted_group);
					return 'sys_id IN ' + ouMemArr.join(',')  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 				
				} else{
					// DFCT0011850 - DFCT0011849 
					ouMemArr = taskPrivacy.getAllUsersAdminsCanTask();
				}
			}
		}		
		// now limit to restricted group, if necessary
		if ( templateData.restricted_group != '') 
			ouMemArr = this.limitUsersToRestrictedGroup(ouMemArr, templateData.restricted_group);
		// turn array into a comma delimitted string.
		var sMems = ouMemArr.join(',');
		// RJ - STRY0065162 - fix issue where all active users was returned for members, instead of only users with Task_User role were returned
		return 'sys_id IN ' + sMems  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 
	},

	getOUMembers: function() {
		return this.privategetOUMembers(current.getValue('primary_assignee'), current.getValue('assignment_group'));
	},

	// task is a single table, template is 3 different tables 
	// using the same routine, but different fields are coming from diffent tables
	privategetOUMembers: function(primary_assignee, assignment_group) 
	{
		// STRY0064991 - get users for members
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		var ouMemArr = [];
		var arrOUs = [];
		// if user is a Task Administrator, return all users

		// STRY0114393 - reorganize code since all cases check Primary Assignee
		// DFCT0012071 - check for null or "null"
		if (primary_assignee == undefined || primary_assignee  == '' || primary_assignee  == null || primary_assignee  == "null"){
			// STRY0114393 - If no Primary assignee set, then return all members a user can task
			// NOTE: this routine handles all roles and accounts for Restricted Groups
			return this.getAllMembersCurrentUserCanTask();
		}
		// DFCT0011930 - user primary assignee to determine Task Administrator permissions
		var isTaskAdministrator = UserPermissions.userIsTaskAdministratorForOU(primary_assignee);
		// DFCT0011930 - user primary assignee to determine Task Executive permissions
		var isTaskExecutive = UserPermissions.userIsTaskExecutiveForOU(primary_assignee);

		// STRY0112587 - STRY0112462 - DFCT0011930
		if (isTaskAdministrator || isTaskExecutive || taskingScripts.ouIsPermissive(primary_assignee)){
			arrOUs.push(primary_assignee);
			// based on note above, if this isn't limitted to primary assignee, just return that load
			ouMemArr = taskingScripts.retrieveMembersInOus(arrOUs);
		}
		// now determine if user is a the Task Manager for the selected Primary Assignee
		// now determine if user is a the Task Manager for the selected Primary Assignee
		else if(UserPermissions.IsUserTaskingAuthority(primary_assignee,gs.getUserID())){
			arrOUs.push(primary_assignee);
			// based on note above, if this isn't limitted to primary assignee, just return that load
			ouMemArr = taskingScripts.retrieveMembersInOus(arrOUs);
		// if user is not a Task Administrator and the user is not a Task Manager in the OU 
		// NOTE :if we drop Primary assignee, this would be a Task Manager in any OU
		// Return this user only as they can work on behalf of
		} else { //} if(UserPermissions.IsUserInOU(primary_assignee,gs.getUserID())){
			if (UserPermissions.IsUserInOU(primary_assignee,gs.getUserID())){
				ouMemArr.push(gs.getUserID());
			} else {
				// If user is not in ou, then return no records
				ouMemArr = ['none'];
			}
		}			
		// now limit to restricted group, if necessary
		if ( assignment_group != '') 
			ouMemArr = this.limitUsersToRestrictedGroup(ouMemArr, assignment_group);
		// turn array into a comma delimitted string.
		var sMems = ouMemArr.join(',');
		// RJ - STRY0065162 - fix issue where all active users was returned for members, instead of only users with Task_User role were returned
		return 'sys_id IN ' + sMems  +''+ '^roles=x_153465_discovert.tasker_user^active=true'; 

	},

	// STRY0064996 - fixed the formatting for this function (no changes made in teh funtion)
	getOfficePicker : function()
	{
		var UserPermissions  = new UserInfoScripts();
		//if(UserPermissions.IsUserTaskingAuthority(current.primary_assignee,gs.getUserID())){

		var currentPrimmaryAssignee = current.primary_assignee;//'5ecc47ed4fca0300303dc3818110c7af';// J1
		var ouOfficePickerArr = '';
		var ouDownOfficePickerArr = '';
		var grParentOffice = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if(grParentOffice.get(currentPrimmaryAssignee)){


			//KTORRES: GET SAME LEVEL OFFICES, BASED ON THE SAME PARENT OFFICE
			ouOfficePickerArr = this.getOfficePickerBasedonParent(grParentOffice.parent);

			//KTORRES: GET THEIR OWN CHAIN OFFICES
			ouDownOfficePickerArr = this.getOfficePickerBasedonParent(currentPrimmaryAssignee);

			if (ouDownOfficePickerArr != '')
				ouOfficePickerArr += (',' +  ouDownOfficePickerArr);
		}
		return 'sys_id IN' + ouOfficePickerArr+'';

		//}
	},

	getOfficePickerBasedonParent : function(parent)
	{
		var ouChildOfficePickerArr = ' ';
		//KTORRES: GET SAME LEVEL OFFICES, BASED ON THE SAME PARENT OFFICE
		var grOffice = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grOffice.addQuery('parent', parent);
		grOffice.orderBy('office_abbreviation');
		grOffice.query();

		while(grOffice.next()){
			if (ouChildOfficePickerArr == ' '){
				ouChildOfficePickerArr += ( grOffice.sys_id);
			}
			else {
				ouChildOfficePickerArr += (',' + grOffice.sys_id);
			}
		}

		return ouChildOfficePickerArr;

	},

