	// DFCT0011926
	_private_getTaskingOfficeList: function(oType, assigned_to, restricted_group) {
		var primary_office = '';
		var recordPrivacy = '';
		primary_office = current.getValue('primary_office') + '';
		recordPrivacy = current.getValue('u_privacy') + '';
		// DFCT0011850 - add primary office and record privacy
		return this._getTaskingOfficeList(oType, assigned_to, restricted_group, primary_office, recordPrivacy);
	},

	// STRY0064996 - load the list of Primary Offices on the TAsk for based on user permissions and system settings
	// STRY0080468 - oType added, Filter OUs internal/external/all
	// DFCT0011926 - passed primary office and record privacy
	_getTaskingOfficeList: function(oType, assigned_to, restricted_group, primary_office, recordPrivacy) {
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		// STRY0139618 - STRY0139619
		var taskPrivacy = new task_privacy();

		var ArrOUs = [];
		var strArrOUs = '';
		// STRY0078831
		var ArrRestrictedOUs = [];
		// STRY0114396
		var au = new global.ArrayUtil();
		var arrUserOUs = [];
		// DFCT0010747
		if(assigned_to != null && assigned_to != ""){
			arrUserOUs = UserPermissions.getUserOffices(assigned_to);
		}
		// STRY0078831 - DFCT0010747 - fixed issue where OUs were not restricted to groups containing members of the restricted group
		if (restricted_group != null && restricted_group != '') {
			ArrRestrictedOUs = UserPermissions.getOUsForRestrictedGroup(restricted_group);
		}
		// STRY0114396 - if assigned member selected, limit to list of OUs for the user
		var aOUResrcictAndUserOnly = [];
		// restricted populated and user ous populated
		if(ArrRestrictedOUs.length > 0 && arrUserOUs.length > 0){
			// restricted group ou's found, union with ou's found for htis user
			aOUResrcictAndUserOnly = au.intersect(arrUserOUs, ArrRestrictedOUs);
		// only restricted array populated
		} else if (ArrRestrictedOUs.length > 0) {
			aOUResrcictAndUserOnly = ArrRestrictedOUs;
		// only user ou array  populated
		} else if (arrUserOUs.length > 0) {
			aOUResrcictAndUserOnly = arrUserOUs;
		}

		// DFCT0011930 - user primary assignee to determine Task Administrator permissions
		var isTaskAdministrator = UserPermissions.userIsTaskAdministratorForOU(primary_office);
		// DFCT0011930 - user primary assignee to determine Task Executive permissions
		var isTaskExecutive = UserPermissions.userIsTaskExecutiveForOU(primary_office);

		// STRY0112587
		if (isTaskAdministrator || isTaskExecutive){
			// STRY0139614 - STRY0139615 - STRY0139616 - STRY0139617 - DFCT0011926 - pass information down from screen instead of pulling from current record
			ArrOUs = taskPrivacy.retrieveAdminTaskOUsPrivacyFiltered(primary_office, recordPrivacy);
		} else {
			// STRY0139618 - STRY0139619
			ArrOUs = taskPrivacy.retrieveTaskOUsPrivacyFiltered(gs.getUserID(), primary_office, recordPrivacy);
		}

		// if nothing returned, no offices will be returned
		if(ArrOUs.length > 0) {
			if (aOUResrcictAndUserOnly.length > 0) {
				// do not add any groups restricting permissions
				ArrOUs = au.intersect(ArrOUs, aOUResrcictAndUserOnly);
			}
			strArrOUs = 'sys_id IN ' + ArrOUs.join(',');
		} else {
			// nothing passed privacy filter, return none
			strArrOUs = 'sys_id INnone';
		}

		strArrOUs = strArrOUs + '^active=true';
		// STRY0080468 - oType added, Filter OUs internal/external/all
		switch(oType){
			case 'internal':
				strArrOUs = strArrOUs + '^u_external_flag=false';
				break;
			case 'external':
				// DFCT0010747
				strArrOUs = '^u_external_flag=true';
				break;
			case 'all':
				// DFCT0010747
				strArrOUs = strArrOUs + '^NQu_external_flag=true';
				break;
		}

		return strArrOUs; 
	},		
	// STRY0065017 - this information is needed in multiple places in the Template Screens for permissions
	getTemplateInfo: function() {
		var templateData = {};
		var templateId = '';
		var assigned_member = '';
		var restrictedGroup = '';
		var primaryAssignee = '';
		var recordPrivacy = '';
		// DFCT0011930
		var primary_office = '';
		var templateLevel = '';
		var templateOU = '';
		var tempDef = '';
		var grTempDef = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
		var recordTable = current.getTableName();

		if(recordTable == 'x_153465_discovert_discover_routing_template'){
			templateId = current.getUniqueValue();
			templateLevel = current.getValue('process_level');
			if(templateLevel == 'ou_process'){
				templateOU = current.getValue('process_ou');
			}
			primaryAssignee = current.getValue('u_primary_assignee');
			// DFCT0011930
			primary_office = current.getValue('u_primary_office');
			restrictedGroup = current.getValue('u_restricted_group');
			// DFCT0012071 - DFCT0012402
			recordPrivacy = current.getValue("u_privacy");
			assigned_member = current.getValue('u_assigned_member') + '';

		} else if(recordTable == 'x_153465_discovert_route_tasks')  {
			tempDef = current.getValue('tasker_process_definition');
			if(grTempDef.get(tempDef)){
				templateId = grTempDef.getUniqueValue();
				templateLevel = grTempDef.getValue('process_level');
				if(templateLevel == 'ou_process'){
					templateOU = grTempDef.getValue('process_ou');
				}
				// DFCT0012402
				recordPrivacy = grTempDef.getValue("u_privacy");
			}
			primaryAssignee = current.getValue('primary_assignee');
			assigned_member = current.getValue('assigned_to_individual') + '';
			// DFCT0011930
			primary_office = current.getValue('primary_office');
			restrictedGroup = current.getValue('assigned_to_group'); 
		} else if(recordTable == 'x_153465_discovert_discover_routing_runtime')  {
			tempDef = current.getValue('routing_template_ref');
			if(grTempDef.get(tempDef)){
				templateId = grTempDef.getUniqueValue();
				templateLevel = grTempDef.getValue('process_level');
				if(templateLevel == 'ou_process'){
					templateOU = grTempDef.getValue('process_ou');
				}
				// DFCT0012402
				recordPrivacy = grTempDef.getValue("u_privacy");
			}
			primaryAssignee = current.getValue('u_primary_assignee');
			assigned_member = current.getValue('u_assigned_member') + '';
			// DFCT0011930
			primary_office = current.getValue('u_primary_office');

			restrictedGroup = current.getValue('u_restricted_group');
		}
		// STRY0079512 3
		restrictedGroup = restrictedGroup == null ? '': restrictedGroup;

		templateData.templateId = templateId;
		templateData.template_level = templateLevel;  
		templateData.template_ou = templateOU;  
		templateData.primary_assignee = primaryAssignee;
		templateData.assigned_member = assigned_member;

		// DFCT0011930
		templateData.primary_office = primary_office;
		// DFCT0012071
		templateData.recordPrivacy = recordPrivacy;
		templateData.restricted_group = restrictedGroup;  			

		return templateData;

	},

	// STRY0065247 - load the list of members a user can task for an OU Template when Primary Assignee not set

	// DFCT0012071					
	_getAllMembersTemplateCanTask: function (template_ou, primary_office, recordPrivacy){
		var taskPrivacy = new task_privacy();
		var arrOUs = taskPrivacy.retrieveTemplateTaskOUsForDesignerPrivacyFiltered(template_ou, primary_office, recordPrivacy);

		// based on note above, if this isn't limitted to primary assignee, just return that load
		var ouMemArr = new tasking_System_Settings_Scripts().retrieveMembersInOus(arrOUs);
		// if no members found, return none
		if(ouMemArr.lengh == 0){
			ouMemArr = ['none'];
		}
		return ouMemArr;
	},

	// STRY0064996 - DFCT0011850 - add primary office
	getTemplateOfficeArray: function(oType, primary_office, assigned_member, recordPrivacy, restricted_group, template_level, template_ou){
		//DFCT0011850 - add primary office
		var strFilter = this._getTemplateOfficeList(oType, restricted_group, primary_office,assigned_member, recordPrivacy, template_level, template_ou);
		return this._getTemplateOfficeArrayFromFilter(strFilter);
	},


	// DFCT0010754 - added another external siganture for ignore assiged member
	getTemplateOfficeListIgnoreAssignedMember: function(oType) {
