	// STRY0065247 - load the list of offices for template design fields
	// STRY0080468 - oType added, Filter OUs internal/external/all
	// DFCT0010754 - made this internal and added 2 different signatures for ignoring assigned member in some cases
	//               added logic for ignore assigned member, the subtask Primary Assignee fields on on Template and Task pass true, everything else will pass nothing
	_private_getTemplateOfficeList: function(oType, ignoreAssignedMember) {
		var templateData = this.getTemplateInfo();
		// STRY0155210 - Template form~ Selecting a primary assignee restricts subtask primary assignee options to only top task primary assignee 
		if(ignoreAssignedMember){
			templateData.assigned_member = null;
		}
		// DFCT0011850 - add primary office and record privacy
		return this._getTemplateOfficeList(oType, templateData.restrictedGroup, templateData.primary_office, templateData.assigned_member, templateData.recordPrivacy, templateData.template_level, templateData.template_ou);
	},

	// STRY0065247 - load the list of offices for template design fields
	_getTemplateOfficeArrayFromFilter: function(strFilter){
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		grOUs.addEncodedQuery(strFilter);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getUniqueValue());
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;
	},

	// STRY0065247 - load the list of offices for template design fields
	// STRY0080468 - oType added, Filter OUs internal/external/all
	_getTemplateOfficeList: function(oType, restrictedGroup, primary_office, assigned_member, recordPrivacy, template_level, template_ou) {
		var templateData = {};
		var taskingScripts = new tasking_System_Settings_Scripts();
		var UserPermissions  = new UserInfoScripts();
		// STRY0139618 - STRY0139619
		var taskPrivacy = new task_privacy();

		var ArrOUs = [];
		var strArrOUs = '';
		// STRY0078831
		var ArrRestrictedOUs = [];
		// STRY0114396
		var au = new global.ArrayUtil();
		var arrUserOUs = [];

		// DFCT0010747
		if(assigned_member != null && assigned_member != "null" && assigned_member != ""){
			arrUserOUs = UserPermissions.getUserOffices(assigned_member);
		}
		// DFCT0010747
		if(restrictedGroup != null && restrictedGroup != "null" && restrictedGroup != ""){
			ArrRestrictedOUs = UserPermissions.getOUsForRestrictedGroup(restrictedGroup);
		}
		// STRY0114396 - if assigned member selected, limit to list of OUs for the user
		var aOUResrcictAndUserOnly = [];
		// restricted populated and user ous populated
		if(ArrRestrictedOUs.length > 0 && arrUserOUs.length > 0){
			// restricted group ou's found, union with ou's found for htis user
			aOUResrcictAndUserOnly = au.intersect(arrUserOUs, ArrRestrictedOUs);
		// only restricted array populated
		} else if (ArrRestrictedOUs.length > 0) {
			aOUResrcictAndUserOnly = ArrRestrictedOUs;
		// only user ou array  populated
		} else if (arrUserOUs.length > 0) {
			aOUResrcictAndUserOnly = arrUserOUs;
		}
		// Get the Template Level, need to check if this object is a Template or a Template Task and grab the Template information based on where coming from
		// STRY0139618 - STRY0139619
		// DFCT0011850 - add primary office
		ArrOUs = taskPrivacy.retrieveTemplateOUsPrivacyFiltered(gs.getUserID(), primary_office, recordPrivacy, template_level, template_ou);
		if(ArrOUs.length > 0){
			// OUs found for this user found, not all ous
			if(aOUResrcictAndUserOnly.length > 0){
				// restricted group ou's found, union with ou's found for htis user
				aOUResrcictAndUserOnly = au.intersect(ArrOUs,aOUResrcictAndUserOnly);
				strArrOUs = 'sys_id IN ' + aOUResrcictAndUserOnly.join(',');
			}else {  // no restricted group set, provide OUs back to user
				strArrOUs = 'sys_id IN ' + ArrOUs.join(',');
			}
		} else {
			if(aOUResrcictAndUserOnly.length > 0){
				// restricted group ou's found and no other OU's found, put only the restricted groups in here
				strArrOUs = 'sys_id IN ' + aOUResrcictAndUserOnly.join(',');
			}
		}
		strArrOUs = strArrOUs + '^active=true';
		// STRY0080468 - oType added, Filter OUs internal/external/all
		switch(oType){
			case 'internal':
				strArrOUs = strArrOUs + '^u_external_flag=false';
				break;
			case 'external':
				// DFCT0010747
				strArrOUs = '^u_external_flag=true';
				break;
			case 'all':
				// DFCT0010747
				strArrOUs = strArrOUs + '^NQu_external_flag=true';
				break;
		}
		return strArrOUs; 
	},

	// receives memberArr and restricted group
	// returnes a memberArr restricted to people in the restricted group
	limitUsersToRestrictedGroup: function(userArr, restricted_group) {
		if (restricted_group == null  || restricted_group == '') {
			/// this should be checked before entering, but if not, just send same array back out
			return userArr;
		}else {

			var UserPermissions  = new UserInfoScripts();
			// STRY0095102 - get the nest list of groups
			// NOTE: may want to look at loading this one time for performance.  
			// If loading, build an object with top group as the key 
			// and the list of all groups under the top group as a comman delimitted string.
			var restricted_group_s = UserPermissions.getRestrictedGroupsAndDescendents(restricted_group);
			var restrictedMemArr = [];
			for (i=0; i<userArr.length; i++) {
				if  (UserPermissions.checkMemberinInGroup(userArr[i],restricted_group_s)) {
					restrictedMemArr.push(userArr[i]);
				}
			}
			return restrictedMemArr;
		}

	},

	type: 'taskerDynamicFilters'
});
